200: const State = struct {
201:     // The effective buffer to process Vietnamese input. we will skip processing if the buffer
202:     // longer than 16.
203:     buffer_effective: [16]Span,
204:     // The maximum buffer length that the engine still keeps the effective buffer, after the maximum
205:     // value (255), we will reset the effective buffer and this value.
206:     buffer_length: u8 = 0,
207:     // Mark the earliest position (inclusive) in buffer where we modified the span, will be used to
208:     // calculate backspaces and replacement characters.
209:     buffer_modification_index: ?u8 = null,
210:     // Mark the position (inclusive) in buffer where we will switch to literal mode (due to manually
211:     // switch, input cancellation, exceed effective buffer). This value is only used in .telex mode
212:     // and the engine is working on position on or after literal index, the engine will skip
213:     // Vietnamese input processing (we only count valid numbers, null mean no literal index).
214:     literal_index: ?u8 = null,
215:     // Determine if we will process input in the specified mode (Telex) or append the character as is.
216:     mode: InputMode = .literal,
217: 
218:     // Initialize the State on allocated memory.
219:     fn init(self: *State) void {
220:         self.* = .{
221:             .buffer_effective = undefined,
222:         };
223:     }
224: 
225:     fn add(self: *State, c: u8) void {
226:         // Only allow a-zA-Z.
227:         assert(std.ascii.isAlphabetic(c));
228: 
229:         // The buffer_modification index must be inbound of the buffer_effective.
230:         assert(self.buffer_modification_index == null or self.buffer_modification_index.? < self.buffer_effective.len);
231: 
232:         // Input mode must be either .literal or .telex.
233:         assert(self.mode == .literal or self.mode == .telex);
234: 
235:         // Should never set literal_index in .literal mode.
236:         if (self.mode == .literal) {
237:             assert(self.literal_index == null);
238:         }
239: 
240:         if (self.literal_index) |literal_index| {
241:             // When literal_index is set, mode must be .telex.
242:             assert(self.mode == .telex);
243:             // The literal_index value must be in range null or 0 -> 16 (buffer_effective length)
244:             // because we won't process Vietnamese input outside the buffer_effective.
245:             assert(literal_index <= self.buffer_effective.len);
246:             // The literal_index value must be less than buffer length.
247:             assert(literal_index < self.buffer_length);
248:         }
249: 
250:         switch (c) {
251:             'A', 'a' => {
252:                 if (self.literal_index != null or self.mode == .literal or self.buffer_length == 0) {
253:                     // 1. Enable literal input when literal_index is set or on literal mode. The
254:                     // literal_index is also set when the word starts with non-Vietnamese onsets.
255:                     // 2. Append literal because no previous span existed. Continue Vietnamese
256:                     // processing on next input.
257:                     self.append_literal(c);
258:                     // Set modification index to null because we didn't modify any existing span.
259:                     self.buffer_modification_index = null;
260:                 } else if (ascii_equal_ignore_case(self.buffer_effective[self.buffer_length - 1].base, c) and self.buffer_effective[self.buffer_length - 1].diacritic == .empty) {
261:                     // 3. Previous span is 'A' or 'a', apply circumflex.
262:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
263:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .circumflex, span_previous.tone);
264:                     // Set modification index for calculating synthetic backspace.
265:                     self.buffer_modification_index = self.buffer_length - 1;
266:                 } else if (ascii_equal_ignore_case(self.buffer_effective[self.buffer_length - 1].base, c) and self.buffer_effective[self.buffer_length - 1].diacritic == .breve) {
267:                     // 4. Previous span is 'Ă' or 'ă', override to circumflex.
268:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
269:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .circumflex, span_previous.tone);
270:                     // Set modification index for calculating synthetic backspace.
271:                     self.buffer_modification_index = self.buffer_length - 1;
272:                 } else if (ascii_equal_ignore_case(self.buffer_effective[self.buffer_length - 1].base, c) and self.buffer_effective[self.buffer_length - 1].diacritic == .circumflex) {
273:                     // 5. Previous span is 'Â' or 'â', cancel circumflex for previous span and append new literal span.
274:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
275:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .empty, span_previous.tone);
276:                     // Set modification index for calculating synthetic backspace.
277:                     self.buffer_modification_index = self.buffer_length - 1;
278:                     // Start literal input from this position.
279:                     self.literal_index = self.buffer_length;
280:                     // Append literal 'A' or 'a'.
281:                     self.append_literal(c);
282:                 } else if (std.ascii.toLower(self.buffer_effective[self.buffer_length - 1].base) != std.ascii.toLower(c)) {
283:                     // 6. Append literal when previous span is not 'A', 'a' and its variants.
284:                     if (self.buffer_length == self.buffer_effective.len) {
285:                         // Start literal input from this position when buffer_length exceeds the buffer_effective.
286:                         self.literal_index = self.buffer_length;
287:                     }
288:                     self.append_literal(c);
289:                     // No modification.
290:                     self.buffer_modification_index = null;
291:                 } else {
292:                     unreachable;
293:                 }
294:             },
295:             'C', 'c' => {}, // fill missing diacritic, e.g. cước.
296:             'D', 'd' => {}, // bar.
297:             'E', 'e' => {
298:                 if (self.literal_index != null or self.mode == .literal or self.buffer_length == 0) {
299:                     // 1. Enable literal input when literal_index is set or on literal mode. The
300:                     // literal_index is also set when the word starts with non-Vietnamese onsets.
301:                     // 2. Append literal because no previous span existed. Continue Vietnamese
302:                     // processing on next input.
303:                     self.append_literal(c);
304:                     // Set modification index to null because we didn't modify any existing span.
305:                     self.buffer_modification_index = null;
306:                 } else if (ascii_equal_ignore_case(self.buffer_effective[self.buffer_length - 1].base, c) and self.buffer_effective[self.buffer_length - 1].diacritic == .empty) {
307:                     // 3. Previous span is 'E' or 'e', apply circumflex.
308:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
309:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .circumflex, span_previous.tone);
310:                     // Set modification index for calculating synthetic backspace.
311:                     self.buffer_modification_index = self.buffer_length - 1;
312:                 } else if (ascii_equal_ignore_case(self.buffer_effective[self.buffer_length - 1].base, c) and self.buffer_effective[self.buffer_length - 1].diacritic == .circumflex) {
313:                     // 4. Previous span is 'Ê' or 'ê', cancel circumflex for previous span and append new literal span.
314:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
315:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .empty, span_previous.tone);
316:                     // Set modification index for calculating synthetic backspace.
317:                     self.buffer_modification_index = self.buffer_length - 1;
318:                     // Start literal input from this position.
319:                     self.literal_index = self.buffer_length;
320:                     // Append literal 'E' or 'e'.
321:                     self.append_literal(c);
322:                 } else if (std.ascii.toLower(self.buffer_effective[self.buffer_length - 1].base) != std.ascii.toLower(c)) {
323:                     // 5. Append literal when previous span is not 'E', 'e' and its variants.
324:                     if (self.buffer_length == self.buffer_effective.len) {
325:                         // Start literal input from this position when buffer_length exceeds the buffer_effective.
326:                         self.literal_index = self.buffer_length;
327:                     }
328:                     self.append_literal(c);
329:                     // No modification.
330:                     self.buffer_modification_index = null;
331:                 } else {
332:                     unreachable;
333:                 }
334:             },
335:             'F', 'f' => {}, // falling.
336:             'I', 'i' => {}, // fill missing diacritic, e.g. người.
337:             'J', 'j' => {}, // falling_glottalized.
338:             'M', 'm' => {}, // fill missing diacritic, e.g. cườm.
339:             'N', 'n' => {}, // fill missing diacritic, e.g. cường.
340:             'O', 'o' => {
341:                 if (self.literal_index != null or self.mode == .literal or self.buffer_length == 0) {
342:                     // 1. Enable literal input when literal_index is set or on literal mode. The
343:                     // literal_index is also set when the word starts with non-Vietnamese onsets.
344:                     // 2. Append literal because no previous span existed. Continue Vietnamese
345:                     // processing on next input.
346:                     self.append_literal(c);
347:                     // Set modification index to null because we didn't modify any existing span.
348:                     self.buffer_modification_index = null;
349:                 } else if (ascii_equal_ignore_case(self.buffer_effective[self.buffer_length - 1].base, c) and self.buffer_effective[self.buffer_length - 1].diacritic == .empty) {
350:                     // 3. Previous span is 'O' or 'o', apply circumflex.
351:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
352:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .circumflex, span_previous.tone);
353:                     // Set modification index for calculating synthetic backspace.
354:                     self.buffer_modification_index = self.buffer_length - 1;
355:                 } else if (ascii_equal_ignore_case(self.buffer_effective[self.buffer_length - 1].base, c) and self.buffer_effective[self.buffer_length - 1].diacritic == .horn) {
356:                     // 4. Previous span is 'Ơ' or 'ơ', override to circumflex.
357:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
358:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .circumflex, span_previous.tone);
359:                     // Set modification index for calculating synthetic backspace
360:                     self.buffer_modification_index = self.buffer_length - 1;
361:                 } else if (ascii_equal_ignore_case(self.buffer_effective[self.buffer_length - 1].base, c) and self.buffer_effective[self.buffer_length - 1].diacritic == .circumflex) {
362:                     // 5. Previous span is 'Ô' or 'ô', cancel circumflex for previous span and append new literal span.
363:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
364:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .empty, span_previous.tone);
365:                     // Set modification index for calculating synthetic backspace.
366:                     self.buffer_modification_index = self.buffer_length - 1;
367:                     // Start literal input from this position.
368:                     self.literal_index = self.buffer_length;
369:                     // Append literal 'O' or 'o'.
370:                     self.append_literal(c);
371:                 } else if (std.ascii.toLower(self.buffer_effective[self.buffer_length - 1].base) != std.ascii.toLower(c)) {
372:                     // 6. Append literal when previous span is not 'O', 'o' and its variants.
373:                     if (self.buffer_length == self.buffer_effective.len) {
374:                         // Start literal input from this position when buffer_length exceeds the buffer_effective.
375:                         self.literal_index = self.buffer_length;
376:                     }
377:                     self.append_literal(c);
378:                     // No modification.
379:                     self.buffer_modification_index = null;
380:                 } else {
381:                     unreachable;
382:                 }
383:             },
384:             'P', 'p' => {}, // fill missing diacritic, e.g. cướp.
385:             'R', 'r' => {}, // dipping_rising.
386:             'S', 's' => {}, // rising.
387:             'T', 't' => {}, // fill missing diacritic, e.g. trượt.
388:             'U', 'u' => {}, // fill missing diacritic, e.g. hươu.
389:             'W', 'w' => {}, // breve.
390:             'X', 'x' => {}, // rising_glottalized.
391:             'Z', 'z' => {}, // level / reset.
392:             else => { // literal.
393:                 // These characters will be added to state literally.
394:                 self.append_literal(c);
395:                 // Set modification index to null because we didn't modify any existing span.
396:                 self.buffer_modification_index = null;
397:                 // Set literal index if it's not set and the length exceed the buffer_effective.
398:                 if (self.literal_index == null and self.buffer_length > self.buffer_effective.len) {
399:                     // Set literal mode since buffer index 16 (just after the last buffer_effective
400:                     // item) because we don't have span for these position, we stop processing Telex
401:                     // rules but we will continue processing if user use backspaces to move back to the
402:                     // buffer_effective range, all existing spans must work as expected.
403:                     self.literal_index = self.buffer_effective.len;
404:                 }
405:             },
406:         }
407: 
408:         // Ensure the literal_index in valid state.
409:         if (self.mode == .literal) {
410:             assert(self.literal_index == null);
411:         }
412:     }
413: 
414:     // Append literal character when possible. Then inclease the buffer_length.
415:     fn append_literal(self: *State, c: u8) void {
416:         // Only allow a-zA-Z.
417:         assert(std.ascii.isAlphabetic(c));
418: 
419:         // Check if we can add new span for input character.
420:         if (self.buffer_length < self.buffer_effective.len) {
421:             // Add character to span.
422:             self.buffer_effective[self.buffer_length] = Span.init(c);
423:         }
424:         // Increase the buffer length for tracking, we will need it went handling backspace.
425:         self.buffer_length = self.buffer_length + 1;
426:     }
427: 
428:     fn backspace(self: *State) void {
429:         // buffer_length must be positive for backspace.
430:         assert(self.buffer_length > 0);
431: 
432:         // Input mode must be either .literal or .telex.
433:         assert(self.mode == .literal or self.mode == .telex);
434: 
435:         if (self.literal_index) |literal_index| {
436:             // Input mode must be .telex when literal_index is set.
437:             assert(self.mode == .telex);
438:             // literal_index must be within buffer range when set.
439:             assert(literal_index < self.buffer_length);
440:         }
441: 
442:         // decrease the buffer_length to match the backspace.
443:         self.buffer_length -= 1;
444:         // because backspace doesn't retro-modify the buffer, unset the buffer_modification_index.
445:         self.buffer_modification_index = null;
446:         // if the literal_index is out of buffer range, unset it.
447:         if (self.literal_index != null and self.literal_index.? == self.buffer_length) {
448:             self.literal_index = null;
449:         }
450:     }
451: };
