670: // Simple ABI wrapper for initialize allocated memory.
671: export fn lex_state_init(state: *anyopaque) void {
672:     // Ensure the allocated memory is aligned.
673:     assert(@intFromPtr(state) % @alignOf(State) == 0);
674: 
675:     const s: *State = @ptrCast(@alignCast(state));
676:     s.init();
677: }
678: 
679: // Needed for the caller to allocate memory for our State.
680: export const lex_state_size: usize = @sizeOf(State);
681: 
682: // Needed for the caller to allocate memory for our State.
683: export const lex_state_alignment: usize = @alignOf(State);
