687: 
688:     // Allocate memory, only specify on this test to simulate runtime allocation.
689:     const raw_pointer = std.testing.allocator.rawAlloc(lex_state_size, .fromByteUnits(lex_state_alignment), @returnAddress()) orelse return error.OutOfMemory;
690:     defer std.testing.allocator.rawFree(raw_pointer[0..lex_state_size], .fromByteUnits(lex_state_alignment), @returnAddress());
691: 
692:     // Initialize state.
693:     lex_state_init(raw_pointer);
694:     const state: *align(lex_state_alignment) State = @ptrCast(@alignCast(raw_pointer));
695:     state.mode = .telex;
696: 
