708:     try expectEqual(null, state.buffer_modification_index);
709:     // Because we didn't exceed the buffer_affective, don't set literal_index.
710:     try expectEqual(null, state.literal_index);
711:     // Don't touch on input mode.
712:     try expectEqual(.telex, state.mode);
713:     // Verify every the spans, must exactly the same with the input.
714:     for (input_sequence, 0..) |c, i| {
715:         const sp = state.buffer_effective[i];
